module top_module (
    input [2:0] d,
    output reg invalid_v
);

    always @(*) begin
        case (d)
            3'b000: invalid_v = 0;
            3'b001: invalid_v = 1;
            3'b010: invalid_v = 1;
            3'b011: invalid_v = 0;
            3'b100: invalid_v = 1;
            3'b101: invalid_v = 0;
            3'b110: invalid_v = 1;
            3'b111: invalid_v = 1;
            default: invalid_v = 0; // Default case
        endcase
    end
endmodule
